// ═══════════════════════════════════════════════════════════════════════════
//  faktura_pdf.js — JEDINÝ generátor PDF faktúr
//
//  Načítava ho appka (prehliadač) aj edge funkcia stripe-webhook (Deno).
//  Dôvod je ten istý, ktorý stojí za `sadzby.js`: doklad kreslený na dvoch
//  miestach sa skôr či neskôr rozíde. Predtým tu boli dve šablóny —
//  `exportFakturaPDF` (zákaznícka) a `saasFakturaPDF` (predplatné) — ktoré
//  zdieľali paletu a font KOPÍROVANÍM. Teraz je šablóna jedna, líšia sa len
//  vstupné dáta a prepínače.
//
//  ČO SEM NEPATRÍ:
//   · `firmaData`, `firmaConfig` a čokoľvek z appky — modul nesmie vedieť,
//     odkiaľ dáta prišli, inak ho edge funkcia nespustí
//   · `window`, `document`, `localStorage` — v Deno neexistujú
//   · sieťové volania — QR sa PODÁVA hotový (viď `opts.qrDataUrl`), aby modul
//     nezávisel od CDN a aby ho Deno vedelo použiť bez `bysquare`/`qrcode`
//
//  jsPDF sa podáva ako parameter, nie berie z globálu — v prehliadači je
//  v `window.jspdf`, v Deno sa importuje. Modul nemá vedieť, ktorý je ktorý.
// ═══════════════════════════════════════════════════════════════════════════

// ── zabudovaný Liberation Sans (29 kB + 28 kB binárne) ──
// V module, nie v HTML: edge funkcia ich potrebuje rovnako ako appka.
const FAKT_FONT_R="";
const FAKT_FONT_B="";

// ── paleta (jediný výskyt; predtým bola skopírovaná v oboch generátoroch) ──
export const PALETA = {
  INK:    [31, 41, 55],
  SOFT:   [90, 102, 117],
  MUTED:  [140, 152, 168],
  LINE:   [224, 230, 238],
  BRAND:  [31, 95, 168],
  BGSOFT: [248, 250, 252],
  BIELA:  [255, 255, 255],
  AKCENT: [240, 138, 36],
  LOGO2:  [157, 184, 216],
};

// ── registrácia unicode fontu (Ľ, Č, Š… — helvetica ich nezvláda) ──
export function registrujFont(doc) {
  try {
    if (typeof FAKT_FONT_R === "undefined") return false;
    doc.addFileToVFS("LibSans-R.ttf", FAKT_FONT_R);
    doc.addFont("LibSans-R.ttf", "LibSans", "normal");
    doc.addFileToVFS("LibSans-B.ttf", FAKT_FONT_B);
    doc.addFont("LibSans-B.ttf", "LibSans", "bold");
    return true;
  } catch (e) {
    console.warn("font sa nepodarilo vložiť:", e);
    return false;
  }
}

// ── pomocné (čisté funkcie, zámerne bez závislosti na appke) ──
const r2 = n => Math.round((+n || 0) * 100) / 100;

export function money(v) {
  const n = (+v || 0).toFixed(2);
  const [ce, de] = n.split(".");
  return ce.replace(/\B(?=(\d{3})+(?!\d))/g, " ") + "," + de;
}
export const eur = v => money(v) + " €";

export function fmtDatum(dt) {
  if (!dt) return "";
  if (/^\d{4}-\d{2}-\d{2}/.test(dt)) {
    const p = dt.slice(0, 10).split("-");
    return +p[2] + ". " + (+p[1]) + ". " + p[0];
  }
  return dt;
}

// ═══════════════════════════════════════════════════════════════════════════
//  VYKRESLENIE
//
//  model = {
//    cislo,
//    dodavatel : { nazov, adresa, ico, dic, icdph, tel, email, zivReg, iban, swift },
//    odberatel : { nazov, adresa, ico, dic, icdph },
//    datumy    : { vystavenie, dodanie, splatnost },
//    platba    : { sposob, vs },
//    popis, polozky:[{nazov,mn,mj,cena}], sumy:{bez,dph,spolu,sadzba},
//    obdobie   : { od, do } | null,
//    poznamka  : string | null
//  }
//  opts = { qrDataUrl, isdoc, patickaCislo }
// ═══════════════════════════════════════════════════════════════════════════
export function vykresliFakturu(jsPDF, model, opts = {}) {
  const doc = new jsPDF({ unit: "mm", format: "a4" });
  const FONT = registrujFont(doc) ? "LibSans" : "helvetica";
  const { INK, SOFT, MUTED, LINE, BRAND, BGSOFT, BIELA, AKCENT, LOGO2 } = PALETA;
  const W = 210, L = 18, R = W - 18;

  const setC = c => doc.setTextColor(c[0], c[1], c[2]);
  const setF = c => doc.setFillColor(c[0], c[1], c[2]);
  const setD = c => doc.setDrawColor(c[0], c[1], c[2]);

  const m   = model.dodavatel || {};
  const odb = model.odberatel || {};
  const dt  = model.datumy || {};
  const pl  = model.platba || {};
  const s   = model.sumy || { bez: 0, dph: 0, spolu: 0, sadzba: 0.23 };
  const sadzbaPct = Math.round((s.sadzba || 0.23) * 100);

  let y = 20;

  // ── HLAVIČKA: logo vľavo, FAKTÚRA + číslo vpravo ──
  const lsz = 11, lx = L, ly = y - 6;
  setF(BRAND); doc.roundedRect(lx, ly, lsz, lsz, 2.5, 2.5, "F");
  doc.setFont(FONT, "bold"); doc.setFontSize(14); setC(BIELA);
  doc.text("e", lx + lsz / 2 - 0.5, y + 1, { align: "center" });
  setF(AKCENT); doc.roundedRect(lx + lsz - 3.7, ly + 1.8, 1.7, 1.7, 0.4, 0.4, "F");
  setF(LOGO2);  doc.roundedRect(lx + lsz - 1.7, ly + 1.8, 1.7, 1.7, 0.4, 0.4, "F");
  doc.roundedRect(lx + lsz - 3.7, ly + 3.8, 1.7, 1.7, 0.4, 0.4, "F");
  doc.setFont(FONT, "bold"); doc.setFontSize(20); setC(INK);
  doc.text("FAKTÚRA", R, y, { align: "right" });
  doc.setFontSize(19); setC(BRAND);
  doc.text(String(model.cislo || ""), R, y + 8, { align: "right" });
  y += 22;

  // ── DODÁVATEĽ / ODBERATEĽ ──
  const colR = L + (R - L) / 2 + 8, halfW = (R - L) / 2 - 6;
  doc.setFont(FONT, "bold"); doc.setFontSize(9); setC(MUTED);
  doc.text("DODÁVATEĽ", L, y); doc.text("ODBERATEĽ", colR, y);
  y += 6;
  doc.setFont(FONT, "bold"); doc.setFontSize(10.5); setC(INK);
  const dNazL = doc.splitTextToSize((m.nazov || "—").replace(/\s+/g, " "), halfW);
  doc.text(dNazL, L, y);
  const oNazL = doc.splitTextToSize(odb.nazov || "—", halfW);
  doc.text(oNazL, colR, y);
  let yd = y + dNazL.length * 5 + 1, yo = y + oNazL.length * 5 + 1;

  doc.setFont(FONT, "normal"); doc.setFontSize(9); setC(SOFT);
  if (m.adresa)   { const a = doc.splitTextToSize(m.adresa, halfW);   doc.text(a, L, yd);    yd += a.length * 4.5 + 1; }
  if (odb.adresa) { const a = doc.splitTextToSize(odb.adresa, halfW); doc.text(a, colR, yo); yo += a.length * 4.5 + 1; }
  yd += 2; yo += 2;

  doc.setFontSize(8.7); setC(SOFT);
  const idLine = (ico, dic, icdph) => {
    const parts = [];
    if (ico)   parts.push("IČO: " + ico);
    if (dic)   parts.push("DIČ: " + dic);
    if (icdph) parts.push("IČ DPH: " + icdph);
    return parts.join("   ");
  };
  doc.text(idLine(m.ico, m.dic, m.icdph), L, yd); yd += 6;
  doc.text(idLine(odb.ico, odb.dic, odb.icdph), colR, yo); yo += 6;

  if (m.tel || m.email) {
    doc.setFont(FONT, "bold"); doc.setFontSize(8.3); setC(MUTED);
    doc.text("KONTAKTNÉ ÚDAJE", L, yd); yd += 4.6;
    doc.setFont(FONT, "normal"); doc.setFontSize(9); setC(SOFT);
    if (m.tel)   { doc.text("tel.: " + m.tel, L, yd);      yd += 4.4; }
    if (m.email) { doc.text("e-mail: " + m.email, L, yd);  yd += 4.4; }
  }
  y = Math.max(yd, yo) + 9;

  // ── DÁTUMY (vľavo) + PLATOBNÝ BLOK (vpravo) ──
  const blokY = y;
  const datum = d => fmtDatum(d) || "—";
  doc.setFontSize(9);
  const dRow = (l, v, b) => {
    doc.setFont(FONT, "normal"); setC(SOFT); doc.text(l, L, y);
    doc.setFont(FONT, b ? "bold" : "normal"); setC(INK); doc.text(v, L + 40, y);
    y += 6;
  };
  dRow("Dátum vystavenia:", datum(dt.vystavenie));
  dRow("Dátum dodania:", datum(dt.dodanie));
  if (dt.splatnost) dRow("Splatnosť:", datum(dt.splatnost), true);

  const qr = opts.qrDataUrl || null;
  const pbX = colR - 6, pbW = R - pbX;
  // výška bloku: základné riadky + IBAN (2 riadky) + SWIFT
  let riadkov = 2;                       // Spôsob úhrady + Suma
  if (pl.vs) riadkov += 1;
  let pbH = riadkov * 5.4 + 8;
  if (m.iban)  pbH += 9.6;
  if (m.swift) pbH += 5.4;
  setF(BGSOFT); setD(LINE); doc.setLineWidth(0.3);
  doc.roundedRect(pbX, blokY - 5, pbW, pbH, 2.5, 2.5, "FD");

  let py = blokY + 1;
  const px = pbX + 5, pvX = pbX + 34, pravyOkraj = pbX + pbW - 5;
  const payR = (l, v, small) => {
    doc.setFont(FONT, "normal"); doc.setFontSize(8.8); setC(SOFT); doc.text(l, px, py);
    doc.setFont(FONT, "bold"); doc.setFontSize(small ? 8 : 9); setC(INK);
    // ak sa hodnota nezmestí od pvX po pravý okraj, ide pod label na plnú šírku
    const sirka = doc.getTextWidth(String(v));
    if (pvX + sirka > pravyOkraj) {
      py += 4.2; doc.setFontSize(8.2);
      let fs = 8.2;
      while (doc.getTextWidth(String(v)) > (pravyOkraj - px) && fs > 6) { fs -= 0.4; doc.setFontSize(fs); }
      doc.text(String(v), px, py); py += 5.4;
    } else {
      doc.text(String(v), pvX, py); py += 5.4;
    }
  };
  payR("Spôsob úhrady:", pl.sposob || "Bankový prevod");
  payR("Suma:", eur(s.spolu));
  if (pl.vs) payR("Variabilný symbol:", pl.vs);
  if (m.iban)  payR("IBAN:", m.iban, true);
  if (m.swift) payR("SWIFT/BIC:", m.swift, true);

  let blokKoniec = blokY - 5 + pbH;
  if (qr) {
    const qsz = 26, qx = pbX + (pbW - qsz) / 2, qy = blokKoniec + 3;
    doc.addImage(qr, "PNG", qx, qy, qsz, qsz);
    doc.setFont(FONT, "normal"); doc.setFontSize(6.8); setC(MUTED);
    doc.text("PAY by square — naskenujte a zaplaťte", pbX + pbW / 2, qy + qsz + 3, { align: "center" });
    blokKoniec = qy + qsz + 5;
  }
  y = Math.max(y, blokKoniec) + 9;

  // ── POPIS ──
  if (model.popis) {
    doc.setFont(FONT, "normal"); doc.setFontSize(9.3); setC(SOFT);
    const pL = doc.splitTextToSize(model.popis, R - L);
    doc.text(pL, L, y); y += pL.length * 4.7 + 7;
  }

  // ── TABUĽKA POLOŽIEK ──
  const cC = L, cNaz = L + 9, cMn = L + (R - L) * 0.50,
        cCena = L + (R - L) * 0.68, cDph = L + (R - L) * 0.79, cSpolu = R;
  doc.setFont(FONT, "bold"); doc.setFontSize(7.8); setC(INK);
  doc.text("Č.", cC, y);
  doc.text("NÁZOV", cNaz, y);
  doc.text("MNOŽSTVO", cMn, y, { align: "right" });
  doc.text("CENA BEZ DPH", cCena, y, { align: "right" });
  doc.text("DPH %", cDph, y, { align: "right" });
  doc.text("SPOLU BEZ DPH", cSpolu, y, { align: "right" });
  y += 2.5; setD(INK); doc.setLineWidth(0.4); doc.line(L, y, R, y); y += 6;
  (model.polozky || []).forEach((p, i) => {
    const bez = r2((+p.mn || 0) * (+p.cena || 0));
    doc.setFont(FONT, "normal"); doc.setFontSize(9.3); setC(INK);
    doc.text(String(i + 1) + ".", cC, y);
    doc.text(doc.splitTextToSize(String(p.nazov || ""), cMn - cNaz - 24)[0], cNaz, y);
    doc.setFont(FONT, "bold"); doc.text(money(p.mn) + (p.mj ? (" " + p.mj) : ""), cMn, y, { align: "right" });
    doc.setFont(FONT, "normal"); doc.text(money(p.cena), cCena, y, { align: "right" });
    setC(SOFT); doc.text(String(sadzbaPct), cDph, y, { align: "right" }); setC(INK);
    doc.setFont(FONT, "bold"); doc.text(money(bez), cSpolu, y, { align: "right" });
    y += 6.5; setD(LINE); doc.setLineWidth(0.3); doc.line(L, y - 2, R, y - 2);
  });
  y += 6;

  // ── OBDOBIE (len faktúra za predplatné) ──
  if (model.obdobie && model.obdobie.od && model.obdobie.do) {
    doc.setFont(FONT, "normal"); doc.setFontSize(8.5); setC(MUTED);
    doc.text("Obdobie: " + fmtDatum(String(model.obdobie.od).slice(0, 10)) +
             " – " + fmtDatum(String(model.obdobie.do).slice(0, 10)), L, y);
    y += 7;
  }

  // ── REKAPITULÁCIA DPH ──
  const rc1 = L, rc2 = L + (R - L) * 0.42, rc3 = L + (R - L) * 0.62, rc4 = L + (R - L) * 0.82;
  doc.setFont(FONT, "normal"); doc.setFontSize(8.3); setC(MUTED);
  doc.text("SADZBA DPH", rc1, y);
  doc.text("ZÁKLAD", rc2, y, { align: "right" });
  doc.text("DPH", rc3, y, { align: "right" });
  doc.text("SPOLU", rc4, y, { align: "right" });
  y += 2.5; setD(LINE); doc.setLineWidth(0.3); doc.line(L, y, rc4 + 2, y); y += 5;
  doc.setFont(FONT, "normal"); doc.setFontSize(9.3); setC(INK);
  doc.text(sadzbaPct + " %", rc1, y);
  doc.text(money(s.bez), rc2, y, { align: "right" });
  doc.text(money(s.dph), rc3, y, { align: "right" });
  doc.text(money(s.spolu), rc4, y, { align: "right" });
  y += 2.5; setD(LINE); doc.line(L, y, rc4 + 2, y); y += 5;
  doc.setFont(FONT, "bold"); setC(INK);
  doc.text("Súčet", rc1, y);
  doc.text(money(s.bez), rc2, y, { align: "right" });
  doc.text(money(s.dph), rc3, y, { align: "right" });
  doc.text(money(s.spolu), rc4, y, { align: "right" });
  y += 6;

  setF(BGSOFT); doc.roundedRect(L, y, R - L, 11, 2, 2, "F");
  doc.setFont(FONT, "bold"); doc.setFontSize(11); setC(INK); doc.text("Spolu", L + 5, y + 7);
  doc.setFontSize(14); setC(BRAND); doc.text(eur(s.spolu), R - 5, y + 7.5, { align: "right" });
  y += 24;

  // ── POZNÁMKA (napr. „uhradené kartou, neuhrádzajte znova") ──
  if (model.poznamka) {
    doc.setFont(FONT, "normal"); doc.setFontSize(8.5); setC(MUTED);
    doc.text(model.poznamka, L, y - 10);
  }

  // ── PODPISOVÁ SEKCIA ──
  const sigX = R - 58, sigCx = sigX + 29;
  doc.setFont(FONT, "bold"); doc.setFontSize(10); setC(INK);
  doc.text((m.nazov || "").split(" - ")[0].replace(/\s+/g, " ").trim(), sigCx, y, { align: "center" });
  doc.setFont(FONT, "normal"); doc.setFontSize(8.3); setC(SOFT);
  let sy = y + 4.5;
  if (m.ico)    { doc.text("IČO " + m.ico, sigCx, sy, { align: "center" }); sy += 4; }
  if (m.zivReg) { doc.text("Živnostenský register: " + m.zivReg, sigCx, sy, { align: "center" }); sy += 4; }
  sy += 8; setD(MUTED); doc.setLineWidth(0.3); doc.line(sigX, sy, sigX + 58, sy); sy += 4.5;
  doc.setFontSize(7.8); setC(MUTED);
  doc.text("Doklad je vystavený elektronicky", sigCx, sy, { align: "center" });
  doc.text("a je platný bez podpisu a pečiatky.", sigCx, sy + 3.5, { align: "center" });

  // ── PÄTIČKA ──
  const fy = 286;
  setD(LINE); doc.setLineWidth(0.3); doc.line(L, fy - 4, R, fy - 4);
  doc.setFont(FONT, "normal"); doc.setFontSize(7.3); setC(MUTED);
  doc.text("Faktúra č. " + (model.cislo || ""), L, fy);
  if (opts.isdoc) doc.text("Doklad obsahuje e-faktúru (ISDOC)", W / 2, fy, { align: "center" });
  doc.text("Vytvorené v eživnostník", R, fy, { align: "right" });

  return doc;
}

// ═══════════════════════════════════════════════════════════════════════════
//  ADAPTÉRY — jediné miesto, kde sa tvar dát appky/DB prekladá na model.
//  Vďaka nim modul nevie nič o `firmaData` ani o tabuľke `saas_faktury`.
// ═══════════════════════════════════════════════════════════════════════════

// Zákaznícka faktúra: tvar `firmaData.faktury[i]` + `meta` + spočítané sumy
export function modelZakaznickejFaktury(f, meta, sumy, settings = {}) {
  const odbNazov = (typeof f.odberatel === "string")
    ? f.odberatel : ((f.odberatel && f.odberatel.nazov) || "");
  return {
    cislo: f.cislo,
    dodavatel: {
      nazov: meta.nazov, adresa: meta.adresa,
      ico: meta.ico, dic: meta.dic, icdph: meta.icdph,
      tel: meta.tel, email: meta.email, zivReg: meta.zivReg,
      iban: meta.iban, swift: meta.swift,
    },
    odberatel: {
      nazov: odbNazov,
      adresa: f.adresa || (f.odberatel && f.odberatel.adresa) || "",
      ico: f.ico, dic: f.dic, icdph: f.icdph,
    },
    datumy: {
      vystavenie: f.vystavenie || f.datum,
      dodanie: f.datum || f.vystavenie,
      splatnost: f.splatnost,
    },
    platba: { sposob: settings.uhrada || "Bankový prevod", vs: f.vs || f.cislo || "—" },
    popis: f.popis || settings.faktText || "",
    polozky: f.polozky || [],
    sumy,
    obdobie: null,
    poznamka: null,
  };
}

// Faktúra za predplatné: tvar riadku tabuľky `saas_faktury`
export function modelSaasFaktury(f, dodavatel) {
  const zaklad = +f.zaklad || 0, dph = +f.dph || 0, spolu = +f.spolu || 0;
  return {
    cislo: f.cislo,
    dodavatel: {
      nazov: dodavatel.nazov, adresa: dodavatel.adresa,
      ico: dodavatel.ico, dic: dodavatel.dic, icdph: dodavatel.icdph,
      email: dodavatel.email, zivReg: dodavatel.zivReg,
      // zámerne bez IBAN — faktúra je zaplatená kartou, výzva na prevod by
      // zvádzala k druhej úhrade
      iban: null, swift: null,
    },
    odberatel: {
      nazov: f.odb_nazov, adresa: f.odb_adresa,
      ico: f.odb_ico, dic: f.odb_dic, icdph: f.odb_icdph,
    },
    datumy: {
      vystavenie: String(f.vystavene || "").slice(0, 10),
      dodanie: String(f.vystavene || "").slice(0, 10),
      splatnost: null,           // uhradené kartou, splatnosť nemá zmysel
    },
    platba: { sposob: "Uhradené kartou", vs: null },
    // Celý popis ide do ODSEKU nad tabuľkou, nie do názvu položky: bunka má
    // 54 mm a `splitTextToSize(...)[0]` v šablóne berie len prvý riadok —
    // dlhý text by sa ticho odsekol uprostred slova.
    popis: f.popis || "eživnostník — predplatné",
    polozky: [{
      nazov: "Predplatné eživnostník",
      mn: 1, mj: "", cena: zaklad,
    }],
    sumy: { bez: zaklad, dph, spolu, sadzba: +f.sadzba_dph || 0.23 },
    // obdobie je súčasťou popisu, druhýkrát ho nevypisujeme
    obdobie: null,
    poznamka: "Faktúra bola uhradená platobnou kartou. Neuhrádzajte ju znova.",
  };
}
